import sys
from collections import defaultdict

MOD = 10**9 + 7

def solve(digitSum: list[int]) -> int:
    n = len(digitSum)
    # dp[i][s] represents the number of valid arrays of length i with the i-th element having digit sum s
    dp = [defaultdict(int) for _ in range(n)]

    # Initialize the first element
    for s in range(0, 51):
        if sum(int(d) for d in str(s)) == digitSum[0]:
            dp[0][s] = 1

    # Fill the dp table
    for i in range(1, n):
        for prev_s in dp[i-1]:
            for curr_s in range(0, 51):
                if sum(int(d) for d in str(curr_s)) == digitSum[i]:
                    if curr_s >= prev_s:
                        dp[i][curr_s] = (dp[i][curr_s] + dp[i-1][prev_s]) % MOD

    # Sum all possibilities for the last element
    return sum(dp[n-1].values()) % MOD
