import sys
from functools import lru_cache

MOD = 10**9 + 7

def solve(digitSum: list[int]) -> int:
    n = len(digitSum)

    # Precompute digit sums for numbers from 0 to 5000
    max_val = 5000
    digit_sums = [0] * (max_val + 1)

    for i in range(max_val + 1):
        s = 0
        num = i
        while num > 0:
            s += num % 10
            num //= 10
        digit_sums[i] = s

    # Precompute count of numbers with a given digit sum
    count = [0] * (max(digitSum) + 1)
    for i in range(max_val + 1):
        count[digit_sums[i]] += 1

    # Dynamic programming to count valid sequences
    @lru_cache(maxsize=None)
    def dp(i, prev):
        if i == n:
            return 1
        total = 0
        for num in range(prev, 5001):
            if digit_sums[num] == digitSum[i]:
                total += dp(i + 1, num)
                total %= MOD
        return total

    return dp(0, 0)
