from functools import lru_cache

MOD = 10**9 + 7

def solve(digitSum: list[int]) -> int:
    n = len(digitSum)

    # Precompute the number of ways to get a digit sum of s with numbers up to 5000
    @lru_cache(maxsize=None)
    def count_numbers(s):
        if s == 0:
            return 1
        res = 0
        for d in range(10):
            if s - d < 0:
                continue
            res += count_numbers(s - d)
            res %= MOD
        return res

    # Precompute the number of ways to get a digit sum of s with numbers up to 5000
    # and store it in a list
    max_digit_sum = 50  # since 5000 has digit sum 5
    dp = [0] * (max_digit_sum + 1)
    for s in range(max_digit_sum + 1):
        dp[s] = count_numbers(s)

    # Now, solve the problem using dynamic programming
    # dp[i][j] = number of ways to form the first i elements of digitSum with the i-th element having digit sum j
    # and being non-decreasing
    # We use a 2D DP array
    dp = [[0] * (max_digit_sum + 1) for _ in range(n)]

    # Base case: first element
    for s in range(max_digit_sum + 1):
        if dp[0][s] == 0:
            dp[0][s] = dp[s]

    # Fill the DP table
    for i in range(1, n):
        for prev_s in range(max_digit_sum + 1):
            for curr_s in range(max_digit_sum + 1):
                if curr_s >= prev_s:
                    dp[i][curr_s] = (dp[i][curr_s] + dp[i-1][prev_s]) % MOD

    # Sum all possibilities for the last element
    result = 0
    for s in range(max_digit_sum + 1):
        result = (result + dp[n-1][s]) % MOD

    return result
